{{(() => {
  const html = (appsmith.store.emailTemplateLiveHtml || (typeof RichTextTemplate.text === 'string' ? RichTextTemplate.text : ((appsmith.store.emailTemplateDraft || {}).html_template || '')));
  const prepared = html
    .split('<br />').join('
')
    .split('<br/>').join('
')
    .split('<br>').join('
')
    .split('<hr />').join('
---
')
    .split('<hr/>').join('
---
')
    .split('<hr>').join('
---
')
    .split('</p>').join('</p>

')
    .split('</div>').join('</div>

')
    .split('</section>').join('</section>

')
    .split('</article>').join('</article>

')
    .split('</blockquote>').join('</blockquote>

')
    .split('</h1>').join('</h1>

')
    .split('</h2>').join('</h2>

')
    .split('</h3>').join('</h3>

')
    .split('</h4>').join('</h4>

')
    .split('</h5>').join('</h5>

')
    .split('</h6>').join('</h6>

')
    .split('</li>').join('</li>
')
    .split('</tr>').join('</tr>
')
    .split('</td>').join('</td>	')
    .split('</th>').join('</th>	');
  const temp = document.createElement('div');
  temp.innerHTML = prepared;
  Array.from(temp.querySelectorAll('li')).forEach((node) => node.insertAdjacentText('afterbegin', '- '));
  const lines = (temp.textContent || '').split('
');
  const output = [];
  let blankRun = 0;
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index].trim();
    if (!line) {
      blankRun += 1;
      if (blankRun <= 1) output.push('');
    } else {
      blankRun = 0;
      output.push(line);
    }
  }
  const text = output.join('
').trim();
  storeValue('emailTemplateDraft', { ...(appsmith.store.emailTemplateDraft || {}), text_template: text, html_template: html });
  storeValue('emailTemplateLiveHtml', html);
  resetWidget('TextareaTextTemplate', true);
  resetWidget('TextareaHtmlTemplate', true);
  resetWidget('RichTextPreview', true);
  showAlert('Plain text output updated', 'success');
})()}}
